#include <bits/stdc++.h>
using namespace std;
int n,q,root,f[500005][21],deep[500005],len[500005];
vector<int> g[500005];
void set_thing(){
    queue<int> b;
    deep[root]=1;
    b.push(root);
    len[root]=-1;
    while(!b.empty()){
        int u=b.front();
        b.pop();
        for(int i=0;i<g[u].size();i++){
            int v=g[u][i];
            if(!deep[v]){
            	len[v]=-1;
                deep[v]=deep[u]+1;
                for(int j=0;j<21 && (f[f[v][j-1]][j-1] || j==0);j++)f[v][j]=(j==0? u:f[f[v][j-1]][j-1]),len[v]++;
                b.push(v);
            }
        }
    }
}
int find_lca(int A,int B){
	int a=A,b=B;
	if(deep[a]<deep[b])swap(a,b);
	//cout<<a<<' '<<b<<endl;
	//跳到同一层 
	int last=len[a]+1;
	while(deep[a]>deep[b]){
		for(int i=min(last-1,len[a]);i>=0;i--)
			if(deep[f[a][i]]>=deep[b]){
				a=f[a][i],last=i;
				break;
			}
	}
	//cout<<a<<' '<<b<<endl;
	//cout<<"deep_equel\n";
	//一起向上跳 
	while(a!=b){
		int last=min(len[a],len[b])+1;
		for(int i=min(last-1,min(len[a],len[b]));i>=0;i--){
			if(f[a][i]!=f[b][i] || (f[a][i]==f[b][i] && i==0)){
				a=f[a][i],b=f[b][i],last=i;
				break;
			}
		}
	}
	//cout<<"got the anser\n";
	return a;
}
int main(){
    cin>>n>>q>>root;
    for(int i=1;i<n;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    set_thing();
    //for(int i=1;i<=n;i++)cout<<deep[i]<<' ';
    //cout<<endl;
    //for(int i=1;i<=n;i++){
    //	cout<<len[i]<<' ';
    //	for(int j=0;j<21 && f[i][j];j++)cout<<f[i][j]<<' ';
    //	cout<<endl;
	//}
	//cout<<"set OK\n";
	while(q--){
		int a,b;
		cin>>a>>b;
		cout<<find_lca(a,b)<<endl;
	}
    return 0;
}
